SourceCode.Declaration:
[DataContractAttribute]
public class ETGVendorOpenTransContract
{
    TransDate asOfDate;
    NoYesId   excludeFutureSettlements;

}

Method.Source:
[
    DataMemberAttribute('AsOfDate'),
    SysOperationLabelAttribute(literalStr("As of date")),
    SysOperationHelpTextAttribute(literalStr("Select the cut-off date for open transactions")),
    SysOperationDisplayOrderAttribute('1')
]
public TransDate parmAsOfDate(TransDate _asOfDate = asOfDate)
{
    asOfDate = _asOfDate;
    return asOfDate;
}

[
    DataMemberAttribute('ExcludeFutureSettlements'),
    SysOperationLabelAttribute(literalStr("Exclude future settlements")),
    SysOperationHelpTextAttribute(literalStr("Exclude settlements made after the as of date")),
    SysOperationDisplayOrderAttribute('2')
]
public NoYesId parmExcludeFutureSettlements(NoYesId _excludeFutureSettlements = excludeFutureSettlements)
{
    excludeFutureSettlements = _excludeFutureSettlements;
    return excludeFutureSettlements;
}
